function path = fPickCalib(cDir,day,fName)%% Returns right calibration file% function pick calibration file%% path = fPickCalib(day,fName)%% day: day string such as '13_0311'.% fName: file name, such as 'DnnVarianCam'% cDir: directory% % path: calibration file path%% Written by Kei Nakamura% 2018/2/8 ver.1: created%%% main bodyfList = dir([cDir,filesep,'*',fName,'*']);   % file listdayE = str2num([day(1:2),day(4:end)]);  % day of the experimentfor i=1:numel(fList)        fNameS = fList(i).name;   % file name string    fDay(i) = str2double(fNameS(1:6));  % day of the fileendk = find(fDay<=dayE,1,'last');  % last one, but before experiment day to pickpath = [cDir,filesep,fList(k).name]; %
